namespace sv_cd096e0b59a747c4ad91306908fc643f.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_cd096e0b59a747c4ad91306908fc643f.Components.Pages.Settings

<nav class="settings-sidebar">
    <ul class="settings-nav">
        @foreach (var section in Sections)
        {
            <li class="settings-nav-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionSelected.InvokeAsync(section)">
                <span class="settings-nav-icon">@GetIcon(section)</span>
                <span class="settings-nav-label">@section</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = { "Profile", "Notifications", "Security", "Appearance" };

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_cd096e0b59a747c4ad91306908fc643f.Components.Pages.Settings
@using sv_cd096e0b59a747c4ad91306908fc643f.Services
@inject ISettingsService SettingsService

<div class="settings-section profile-section">
    <h2>Profile Settings</h2>

    @if (_loading)
    {
        <p class="loading">Loading profile...</p>
    }
    else
    {
        <div class="profile-form">
            <div class="avatar-preview">
                <img src="@_avatarUrl" alt="Avatar" class="avatar-image" />
                <div class="avatar-url">
                    <label for="avatarUrl">Avatar URL</label>
                    <input id="avatarUrl" type="url" @bind="_avatarUrl" placeholder="https://example.com/avatar.png" />
                </div>
            </div>

            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" @bind="_displayName" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" @bind="_email" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" @bind="_bio" rows="4" placeholder="Tell us about yourself..."></textarea>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveChanges" disabled="@_saving">
                    @(_saving ? "Saving..." : "Save Changes")
                </button>
                <button class="btn btn-secondary" @onclick="DiscardChanges" disabled="@_saving">
                    Discard Changes
                </button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Profile saved successfully!</div>
            }
            @if (_errorMessage is not null)
            {
                <div class="toast toast-error">@_errorMessage</div>
            }
        </div>
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
    }

    private async Task LoadProfile()
    {
        _loading = true;
        try
        {
            _savedProfile = await SettingsService.GetProfileAsync();
            ApplyProfile(_savedProfile);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load profile: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveChanges()
    {
        _saving = true;
        _showSuccess = false;
        _errorMessage = null;
        try
        {
            var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            _showSuccess = true;
            _ = HideSuccessAfterDelay();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _errorMessage = null;
        _showSuccess = false;
    }
}

@namespace sv_cd096e0b59a747c4ad91306908fc643f.Components.Pages.Settings
@using sv_cd096e0b59a747c4ad91306908fc643f.Services
@inject ISettingsService SettingsService

<div class="settings-section notifications-section">
    <h2>Notification Preferences</h2>

    @if (_loading)
    {
        <p class="loading">Loading preferences...</p>
    }
    else
    {
        <div class="notification-toggles">
            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_emailNotifications" class="toggle-input" />
                    <span class="toggle-switch"></span>
                    <span class="toggle-text">Email Notifications</span>
                </label>
            </div>

            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_pushNotifications" class="toggle-input" />
                    <span class="toggle-switch"></span>
                    <span class="toggle-text">Push Notifications</span>
                </label>
            </div>

            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_weeklyDigest" class="toggle-input" />
                    <span class="toggle-switch"></span>
                    <span class="toggle-text">Weekly Digest</span>
                </label>
            </div>
        </div>

        <div class="muted-channels">
            <h3>Muted Channels</h3>
            @if (_allChannels.Count == 0)
            {
                <p class="empty-state">No channels available.</p>
            }
            else
            {
                <ul class="channel-list">
                    @foreach (var channel in _allChannels)
                    {
                        <li class="channel-item">
                            <label>
                                <input type="checkbox"
                                       checked="@_mutedChannels.Contains(channel)"
                                       @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                                <span>@channel</span>
                            </label>
                        </li>
                    }
                </ul>
            }
        </div>

        <div class="form-actions">
            <button class="btn btn-primary" @onclick="SavePreferences" disabled="@_saving">
                @(_saving ? "Saving..." : "Save Preferences")
            </button>
        </div>

        @if (_showSuccess)
        {
            <div class="toast toast-success">Preferences saved successfully!</div>
        }
        @if (_errorMessage is not null)
        {
            <div class="toast toast-error">@_errorMessage</div>
        }
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private List<string> _allChannels = new() { "general", "announcements", "engineering", "design", "marketing", "support" };
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = prefs.EmailNotifications;
            _pushNotifications = prefs.PushNotifications;
            _weeklyDigest = prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load preferences: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        _saving = true;
        _showSuccess = false;
        _errorMessage = null;
        try
        {
            var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _showSuccess = true;
            _ = HideSuccessAfterDelay();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_cd096e0b59a747c4ad91306908fc643f.Components.Pages.Settings
@using sv_cd096e0b59a747c4ad91306908fc643f.Services
@inject ISettingsService SettingsService

<div class="change-password-panel">
    <button class="panel-header" @onclick="ToggleExpanded">
        <span class="panel-title">Change Password</span>
        <span class="panel-toggle">@(_expanded ? "▲" : "▼")</span>
    </button>

    @if (_expanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label for="currentPassword">Current Password</label>
                <input id="currentPassword" type="password" @bind="_currentPassword" />
            </div>

            <div class="form-group">
                <label for="newPassword">New Password</label>
                <input id="newPassword" type="password" @bind="_newPassword" />
            </div>

            <div class="form-group">
                <label for="confirmPassword">Confirm New Password</label>
                <input id="confirmPassword" type="password" @bind="_confirmPassword" />
            </div>

            @if (_validationError is not null)
            {
                <div class="validation-error">@_validationError</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                @(_saving ? "Updating..." : "Update Password")
            </button>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Password updated successfully!</div>
            }
            @if (_errorMessage is not null)
            {
                <div class="toast toast-error">@_errorMessage</div>
            }
        </div>
    }
</div>

@code {
    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _validationError;
    private string? _errorMessage;
    private bool _saving;
    private bool _showSuccess;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task UpdatePassword()
    {
        _validationError = null;
        _errorMessage = null;
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _validationError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _validationError = "New password is required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _validationError = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _showSuccess = true;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _ = HideSuccessAfterDelay();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to update password: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

