<div class="active-sessions">
    <h3>Active Sessions</h3>

    @if (Sessions is null || Sessions.Count == 0)
    {
        <p class="empty-state">No active sessions found.</p>
    }
    else
    {
        <table class="sessions-table">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("g")</td>
                        <td>
                            @if (session.Id != CurrentSessionId)
                            {
                                <button class="btn btn-danger btn-sm" @onclick="() => PromptRevoke(session)">
                                    Revoke
                                </button>
                            }
                            else
                            {
                                <span class="current-session-badge">Current</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }

    @if (_sessionToRevoke is not null)
    {
        <div class="modal-overlay" @onclick="CancelRevoke">
            <div class="modal-dialog" @onclick:stopPropagation="true">
                <h4>Confirm Session Revocation</h4>
                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                <div class="modal-actions">
                    <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @(_revoking ? "Revoking..." : "Revoke Session")
                    </button>
                    <button class="btn btn-secondary" @onclick="CancelRevoke" disabled="@_revoking">
                        Cancel
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = new();
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        try
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
        finally
        {
            _revoking = false;
        }
    }
}

@namespace sv_cd096e0b59a747c4ad91306908fc643f.Components.Pages.Settings
