@code {
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private string _currentSessionId = "";
    private bool _loading = true;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = settings.TwoFactorEnabled;
            _lastPasswordChange = settings.LastPasswordChange;
            _sessions = settings.Sessions;
            // Assume first session is current
            _currentSessionId = _sessions.FirstOrDefault()?.Id ?? "";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load security settings: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RevokeSession(string sessionId)
    {
        _errorMessage = null;
        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to revoke session: {ex.Message}";
        }
    }
}

