            </div>

            <div class="form-group">
                <label for="confirmPassword">Confirm New Password</label>
                <input id="confirmPassword" type="password" @bind="_confirmPassword" />
            </div>

            @if (_validationError is not null)
            {
                <div class="validation-error">@_validationError</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                @(_saving ? "Updating..." : "Update Password")
            </button>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Password updated successfully!</div>
