    private string? _errorMessage;
    private bool _saving;
    private bool _showSuccess;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task UpdatePassword()
    {
        _validationError = null;
        _errorMessage = null;
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _validationError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _validationError = "New password is required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _validationError = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _showSuccess = true;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _ = HideSuccessAfterDelay();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to update password: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

