    [Parameter] public List<ActiveSession> Sessions { get; set; } = new();
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        try
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
        finally
        {
            _revoking = false;
        }
    }
}
"}

{"path": "/tmp/sv-cd096e0b59a747c4ad91306908fc643f/Components/Pages/Settings/SecuritySection.razor", "file_text": "@namespace sv_cd096e0b59a747c4ad91306908fc643f.Components.Pages.Settings
@using sv_cd096e0b59a747c4ad91306908fc643f.Services
@inject ISettingsService SettingsService

<div class="settings-section security-section">
    <h2>Security Settings</h2>

    @if (_loading)
    {
        <p class="loading">Loading security settings...</p>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="two-factor-section">
            <h3>Two-Factor Authentication</h3>
            <div class="two-factor-status">
                <label class="toggle-label">
                    <input type="checkbox" checked="@_twoFactorEnabled" disabled class="toggle-input" />
                    <span class="toggle-switch"></span>
                    <span class="toggle-text">Two-Factor Authentication</span>
                </label>
                <span class="status-indicator @(_twoFactorEnabled ? "status-enabled" : "status-disabled")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <p class="last-password-change">Last password change: @_lastPasswordChange.Value.ToString("f")</p>
            }
        </div>

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_currentSessionId"
                             OnRevoke="RevokeSession" />

        @if (_errorMessage is not null)
        {
            <div class="toast toast-error">@_errorMessage</div>
        }
    }
</div>

@code {
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private string _currentSessionId = "";
    private bool _loading = true;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = settings.TwoFactorEnabled;
            _lastPasswordChange = settings.LastPasswordChange;
            _sessions = settings.Sessions;
            // Assume first session is current
            _currentSessionId = _sessions.FirstOrDefault()?.Id ?? "";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load security settings: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RevokeSession(string sessionId)
    {
        _errorMessage = null;
        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to revoke session: {ex.Message}";
        }
    }
}
"}

{"path": "/tmp/sv-cd096e0b59a747c4ad91306908fc643f/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@namespace sv_cd096e0b59a747c4ad91306908fc643f.Components.Pages.Settings
@using sv_cd096e0b59a747c4ad91306908fc643f.Services
@inject ISettingsService SettingsService

<div class="settings-section appearance-section">
    <h2>Appearance Settings</h2>

    @if (_loading)
    {
        <p class="loading">Loading appearance settings...</p>
    }
    else
    {
        <div class="appearance-form">
            <div class="form-group">
                <h3>Theme</h3>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-label">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <h3>Font Size</h3>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-label">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label for="language">Language</label>
                <select id="language" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang.Key">@lang.Value</option>
                    }
                </select>
            </div>

            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_compactMode" class="toggle-input" />
                    <span class="toggle-switch"></span>
                    <span class="toggle-text">Compact Mode</span>
                </label>
            </div>

            <div class="appearance-preview" style="@GetPreviewStyle()">
                <h4>Live Preview</h4>
                <p>This is how your content will look with the selected settings.</p>
                <div class="preview-card">
                    <strong>Sample Card</strong>
                    <p>Lorem ipsum dolor sit amet, consectetur adipiscing elit.</p>
                    <button class="btn btn-primary">Action Button</button>
                </div>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                    @(_saving ? "Saving..." : "Save")
                </button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Appearance saved successfully!</div>
            }
            @if (_errorMessage is not null)
            {
                <div class="toast toast-error">@_errorMessage</div>
            }
        </div>
    }
</div>

@code {
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;
    private string? _errorMessage;

    private static readonly string[] _themes = { "Light", "Dark", "System" };
    private static readonly string[] _fontSizes = { "Small", "Medium", "Large" };
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Spanish",
        ["fr"] = "French",
        ["de"] = "German",
        ["ja"] = "Japanese",
        ["zh"] = "Chinese"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load appearance settings: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private string GetPreviewStyle()
    {
        var bg = _theme switch
        {
            "Light" => "background-color: #ffffff; color: #1a1a1a;",
            "Dark" => "background-color: #1a1a2e; color: #e0e0e0;",
            _ => "background-color: #f5f5f5; color: #333333;"
        };

        var font = _fontSize switch
        {
            "Small" => "font-size: 12px;",
            "Large" => "font-size: 18px;",
            _ => "font-size: 14px;"
        };

        var padding = _compactMode ? "padding: 8px;" : "padding: 16px;";

        return $"{bg} {font} {padding}";
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        _showSuccess = false;
        _errorMessage = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _showSuccess = true;
            _ = HideSuccessAfterDelay();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
"}

