@namespace sv_cd096e0b59a747c4ad91306908fc643f.Components.Pages.Settings
@using sv_cd096e0b59a747c4ad91306908fc643f.Services
@inject ISettingsService SettingsService

<div class="change-password-panel">
    <button class="panel-header" @onclick="ToggleExpanded">
        <span class="panel-title">Change Password</span>
        <span class="panel-toggle">@(_expanded ? "▲" : "▼")</span>
    </button>

    @if (_expanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label for="currentPassword">Current Password</label>
                <input id="currentPassword" type="password" @bind="_currentPassword" />
            </div>

            <div class="form-group">
                <label for="newPassword">New Password</label>
                <input id="newPassword" type="password" @bind="_newPassword" />
            </div>

            <div class="form-group">
                <label for="confirmPassword">Confirm New Password</label>
                <input id="confirmPassword" type="password" @bind="_confirmPassword" />
            </div>

            @if (_validationError is not null)
            {
                <div class="validation-error">@_validationError</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_saving">
                @(_saving ? "Updating..." : "Update Password")
            </button>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Password updated successfully!</div>
            }
            @if (_errorMessage is not null)
            {
                <div class="toast toast-error">@_errorMessage</div>
            }
        </div>
    }
</div>

@code {
    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _validationError;
    private string? _errorMessage;
    private bool _saving;
    private bool _showSuccess;

    private void ToggleExpanded() => _expanded = !_expanded;

    private async Task UpdatePassword()
    {
        _validationError = null;
        _errorMessage = null;
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _validationError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _validationError = "New password is required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _validationError = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _showSuccess = true;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _ = HideSuccessAfterDelay();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to update password: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

