@namespace sv_cd096e0b59a747c4ad91306908fc643f.Components.Pages.Settings
@using sv_cd096e0b59a747c4ad91306908fc643f.Services
@inject ISettingsService SettingsService

<div class="settings-section security-section">
    <h2>Security Settings</h2>

    @if (_loading)
    {
        <p class="loading">Loading security settings...</p>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="two-factor-section">
            <h3>Two-Factor Authentication</h3>
            <div class="two-factor-status">
                <label class="toggle-label">
                    <input type="checkbox" checked="@_twoFactorEnabled" disabled class="toggle-input" />
                    <span class="toggle-switch"></span>
                    <span class="toggle-text">Two-Factor Authentication</span>
                </label>
                <span class="status-indicator @(_twoFactorEnabled ? "status-enabled" : "status-disabled")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <p class="last-password-change">Last password change: @_lastPasswordChange.Value.ToString("f")</p>
            }
        </div>

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_currentSessionId"
                             OnRevoke="RevokeSession" />

        @if (_errorMessage is not null)
        {
            <div class="toast toast-error">@_errorMessage</div>
        }
    }
</div>

@code {
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private string _currentSessionId = "";
    private bool _loading = true;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = settings.TwoFactorEnabled;
            _lastPasswordChange = settings.LastPasswordChange;
            _sessions = settings.Sessions;
            // Assume first session is current
            _currentSessionId = _sessions.FirstOrDefault()?.Id ?? "";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load security settings: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RevokeSession(string sessionId)
    {
        _errorMessage = null;
        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to revoke session: {ex.Message}";
        }
    }
}

