toolArgs.file_text:
.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* Sidebar */
.settings-sidebar {
    width: 240px;
    background-color: var(--sidebar-bg, #f8f9fa);
    border-right: 1px solid var(--border-color, #e0e0e0);
    padding: 1rem 0;
    flex-shrink: 0;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.5rem;
    cursor: pointer;
    transition: background-color 0.2s, border-left 0.2s;
    border-left: 3px solid transparent;
    color: var(--text-secondary, #555);
}

.settings-nav-item:hover {
    background-color: var(--hover-bg, #e9ecef);
}

.settings-nav-item.active {
    background-color: var(--active-bg, #e3f2fd);
    border-left-color: var(--primary-color, #1976d2);
    color: var(--primary-color, #1976d2);
    font-weight: 600;
}

.settings-nav-icon {
    font-size: 1.2rem;
}

/* Content area */
.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 800px;
}

.settings-section h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    font-size: 1.5rem;
    color: var(--text-primary, #1a1a1a);
}

/* Form elements */
.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.375rem;
    font-weight: 500;
    color: var(--text-secondary, #555);
}

.form-group input[type="text"],
.form-group input[type="email"],
.form-group input[type="url"],
.form-group input[type="password"],
.form-group textarea,
.form-group select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid var(--border-color, #ccc);
    border-radius: 6px;
    font-size: 0.95rem;
    transition: border-color 0.2s;
}

.form-group input:focus,
.form-group textarea:focus,
.form-group select:focus {
    outline: none;
    border-color: var(--primary-color, #1976d2);
    box-shadow: 0 0 0 2px rgba(25, 118, 210, 0.15);
}

.form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

/* Buttons */
.btn {
    padding: 0.5rem 1.25rem;
    border: none;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: background-color 0.2s, opacity 0.2s;
}

.btn:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-primary {
    background-color: var(--primary-color, #1976d2);
    color: white;
}

.btn-primary:hover:not(:disabled) {
    background-color: #1565c0;
}

.btn-secondary {
    background-color: var(--secondary-bg, #e0e0e0);
    color: var(--text-primary, #333);
}

.btn-secondary:hover:not(:disabled) {
    background-color: #d0d0d0;
}

.btn-danger {
    background-color: #d32f2f;
    color: white;
}

.btn-danger:hover:not(:disabled) {
    background-color: #b71c1c;
}

.btn-sm {
    padding: 0.3rem 0.75rem;
    font-size: 0.8rem;
}

/* Toggle switches */
.toggle-group {
    margin-bottom: 1rem;
}

.toggle-label {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    cursor: pointer;
}

.toggle-input {
    width: 18px;
    height: 18px;
    accent-color: var(--primary-color, #1976d2);
}

.toggle-text {
    font-size: 0.95rem;
}

/* Toast notifications */
.toast {
    margin-top: 1rem;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    font-size: 0.9rem;
    animation: slideIn 0.3s ease;
}

.toast-success {
    background-color: #e8f5e9;
    color: #2e7d32;
    border: 1px solid #a5d6a7;
}

.toast-error {
    background-color: #ffebee;
    color: #c62828;
    border: 1px solid #ef9a9a;
}

@keyframes slideIn {
    from { opacity: 0; transform: translateY(-10px); }
    to { opacity: 1; transform: translateY(0); }
}

/* Avatar */
.avatar-preview {
    display: flex;
    align-items: center;
    gap: 1.5rem;
    margin-bottom: 1.5rem;
    padding: 1rem;
    background: var(--card-bg, #f5f5f5);
    border-radius: 8px;
}

.avatar-image {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    background-color: #e0e0e0;
}

.avatar-url {
    flex: 1;
}

.avatar-url label {
    display: block;
    margin-bottom: 0.375rem;
    font-weight: 500;
    color: var(--text-secondary, #555);
}

.avatar-url input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid var(--border-color, #ccc);
    border-radius: 6px;
    font-size: 0.9rem;
}

/* Muted channels */
.muted-channels {
    margin-top: 2rem;
}

.muted-channels h3 {
    margin-bottom: 0.75rem;
}

.channel-list {
    list-style: none;
    padding: 0;
}

.channel-item {
    padding: 0.5rem 0;
    border-bottom: 1px solid var(--border-color, #eee);
}

.channel-item label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
}

/* Change password panel */
.change-password-panel {
    margin-bottom: 2rem;
    border: 1px solid var(--border-color, #e0e0e0);
    border-radius: 8px;
    overflow: hidden;
}

.panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 1rem 1.25rem;
    background: var(--card-bg, #f8f9fa);
    border: none;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 500;
}

.panel-header:hover {
    background: var(--hover-bg, #e9ecef);
}

.panel-body {
    padding: 1.25rem;
}

.validation-error {
    color: #d32f2f;
    font-size: 0.85rem;
    margin-bottom: 0.75rem;
}

/* Two-factor */
.two-factor-section {
    margin-bottom: 2rem;
}

.two-factor-status {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.status-indicator {
    padding: 0.25rem 0.75rem;
    border-radius: 12px;
    font-size: 0.8rem;
    font-weight: 600;
}

.status-enabled {
    background-color: #e8f5e9;
    color: #2e7d32;
}

.status-disabled {
    background-color: #ffebee;
    color: #c62828;
}

.last-password-change {
    margin-top: 0.5rem;
    font-size: 0.85rem;
    color: var(--text-secondary, #777);
}

/* Sessions table */
.sessions-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 1rem;
}

.sessions-table th,
.sessions-table td {
    padding: 0.75rem;
    text-align: left;
    border-bottom: 1px solid var(--border-color, #e0e0e0);
}

.sessions-table th {
    font-weight: 600;
    color: var(--text-secondary, #555);
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.current-session-badge {
    font-size: 0.8rem;
    color: var(--primary-color, #1976d2);
    font-weight: 500;
}

/* Modal */
.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.modal-dialog {
    background: white;
    border-radius: 12px;
    padding: 2rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
}

.modal-dialog h4 {
    margin-top: 0;
}

.modal-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

/* Appearance preview */
.appearance-preview {
    margin-top: 1.5rem;
    border: 1px solid var(--border-color, #e0e0e0);
    border-radius: 8px;
    transition: all 0.3s ease;
}

.appearance-preview h4 {
    margin-top: 0;
}

.preview-card {
    margin-top: 1rem;
    padding: 1rem;
    border: 1px solid rgba(128, 128, 128, 0.3);
    border-radius: 6px;
}

/* Radio groups */
.radio-group {
    display: flex;
    gap: 1.5rem;
    margin-top: 0.5rem;
}

.radio-label {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
}

/* Loading state */
.loading {
    color: var(--text-secondary, #777);
    font-style: italic;
}

.empty-state {
    color: var(--text-secondary, #999);
    font-style: italic;
}

